// POST /api/tickets/[id]/manager-approval  — agent requests manager approval
// PATCH /api/tickets/[id]/manager-approval — manager approves or rejects
import { NextRequest } from 'next/server'
import { prisma } from '@/lib/prisma'
import { requireAuth, getTenantId, successResponse, errorResponse } from '@/lib/api'
import nodemailer from 'nodemailer'

const AGENT_ROLES = ['IT_AGENT', 'TENANT_ADMIN', 'SUPER_ADMIN']

async function sendManagerEmail(tenantId: string, to: { name: string; email: string }, subject: string, html: string) {
  try {
    const smtp = await prisma.smtpConfig.findUnique({ where: { tenantId } })
    if (!smtp?.isEnabled || !smtp.host) return
    const transport = nodemailer.createTransport({
      host: smtp.host, port: smtp.port, secure: smtp.secure,
      auth: { user: smtp.username, pass: smtp.password },
    })
    await transport.sendMail({ from: `"${smtp.fromName}" <${smtp.fromEmail}>`, to: to.email, subject, html })
  } catch (e) { console.error('Manager email failed:', e) }
}

// ── POST — agent requests manager approval ─────────────────────────────────
export async function POST(req: NextRequest, { params }: { params: Promise<{ id: string }> }) {
  const { error, session } = await requireAuth()
  if (error) return error
  const tenantId = getTenantId(session!)
  if (!tenantId) return errorResponse('No tenant', 400)
  const { id } = await params

  const role        = (session!.user as any).role       as string
  const isDeptAdmin = (session!.user as any).isDeptAdmin as boolean | undefined
  if (!AGENT_ROLES.includes(role) && !isDeptAdmin) return errorResponse('Forbidden', 403)

  const ticket = await prisma.ticket.findFirst({
    where: { id, tenantId },
    include: {
      submitter: { select: { id: true, name: true, email: true, role: true, managerId: true, manager: { select: { id: true, name: true, email: true } } } },
    },
  })
  if (!ticket) return errorResponse('Ticket not found', 404)

  // Only for staff tickets
  if (ticket.submitter.role !== 'STAFF') {
    return errorResponse('Manager approval can only be requested for tickets submitted by STAFF members', 400)
  }

  // Submitter must have a manager
  if (!ticket.submitter.manager) {
    return errorResponse('The ticket submitter does not have a manager assigned. Set a "Reports To" manager in user management.', 400)
  }

  // Prevent duplicate requests
  if (ticket.managerApprovalStatus === 'PENDING') {
    return errorResponse('A manager approval request is already pending for this ticket', 409)
  }

  const body = await req.json().catch(() => ({}))
  const note: string = body.note ?? ''

  // Update ticket
  const updated = await prisma.ticket.update({
    where: { id },
    data: {
      managerApprovalStatus:      'PENDING',
      managerApprovalRequestedAt: new Date(),
      managerApprovalRespondedAt: null,
      managerApprovalNote:        note || null,
      requestedManagerId:         ticket.submitter.manager.id,
    },
  })

  // In-app notification for manager
  await prisma.notification.create({
    data: {
      tenantId,
      userId:  ticket.submitter.manager.id,
      title:   `Approval requested on ticket #${ticket.ticketNumber}`,
      body:    `${session!.user.name} is requesting your approval on ticket: "${ticket.title}"`,
      ticketId: id,
    },
  }).catch(() => {})

  // Activity log
  await prisma.ticketActivity.create({
    data: {
      ticketId: id, actorId: session!.user.id,
      type: 'MANAGER_APPROVAL_REQUESTED',
      meta: JSON.stringify({ managerId: ticket.submitter.manager.id, managerName: ticket.submitter.manager.name, note }),
    },
  }).catch(() => {})

  // Email the manager
  sendManagerEmail(
    tenantId,
    ticket.submitter.manager,
    `[Ticket #${ticket.ticketNumber}] Approval requested — ${ticket.title}`,
    `<div style="font-family:Arial,sans-serif;max-width:560px;margin:0 auto">
      <div style="background:#1E1B4B;padding:20px 24px;border-radius:8px 8px 0 0">
        <h2 style="color:white;margin:0;font-size:18px">Manager Approval Requested</h2>
      </div>
      <div style="background:white;border:1px solid #E2E8F0;border-top:none;padding:24px;border-radius:0 0 8px 8px">
        <p style="margin:0 0 16px;color:#374151">Hi <strong>${ticket.submitter.manager.name}</strong>,</p>
        <p style="margin:0 0 16px;color:#374151">
          <strong>${session!.user.name}</strong> is requesting your approval on the following ticket
          submitted by <strong>${ticket.submitter.name}</strong>:
        </p>
        <div style="background:#F8FAFC;border-left:4px solid #F59E0B;padding:14px 18px;border-radius:4px;margin:16px 0">
          <div style="font-weight:700;color:#1E293B;margin-bottom:4px">#${ticket.ticketNumber} — ${ticket.title}</div>
          <div style="font-size:13px;color:#64748B;margin-top:6px">Department: ${ticket.department} &nbsp;·&nbsp; Priority: ${ticket.priority}</div>
          ${note ? `<div style="margin-top:10px;font-size:13px;color:#374151"><strong>Note:</strong> ${note}</div>` : ''}
        </div>
        <p style="margin:16px 0 0;color:#374151">
          Please log in to EduDesk to review the ticket and provide your approval or rejection.
        </p>
        <p style="margin:8px 0 0;color:#94A3B8;font-size:12px">
          Go to the portal → Approval Requests to respond.
        </p>
      </div>
    </div>`,
  )

  return successResponse(updated)
}

// ── PATCH — manager responds (approve or reject) ────────────────────────────
export async function PATCH(req: NextRequest, { params }: { params: Promise<{ id: string }> }) {
  const { error, session } = await requireAuth()
  if (error) return error
  const tenantId = getTenantId(session!)
  if (!tenantId) return errorResponse('No tenant', 400)
  const { id } = await params

  const userId = session!.user.id

  const ticket = await prisma.ticket.findFirst({
    where: { id, tenantId },
    include: {
      submitter: { select: { id: true, name: true } },
      assignee:  { select: { id: true, name: true } },
    },
  })
  if (!ticket) return errorResponse('Ticket not found', 404)

  // Only the requested manager may respond
  if (ticket.requestedManagerId !== userId) {
    return errorResponse('Only the requested manager can approve or reject this ticket', 403)
  }

  if (ticket.managerApprovalStatus !== 'PENDING') {
    return errorResponse('This approval request is no longer pending', 409)
  }

  const body = await req.json()
  const { decision, note } = body
  if (!['APPROVED', 'REJECTED'].includes(decision)) {
    return errorResponse('decision must be APPROVED or REJECTED', 400)
  }

  const updated = await prisma.ticket.update({
    where: { id },
    data: {
      managerApprovalStatus:      decision,
      managerApprovalRespondedAt: new Date(),
      managerApprovalNote:        note ?? null,
    },
  })

  // Notify the assignee (or ticket creator if unassigned)
  const notifyUserId = ticket.assigneeId ?? ticket.submitterId
  await prisma.notification.create({
    data: {
      tenantId,
      userId:  notifyUserId,
      title:   `Manager ${decision === 'APPROVED' ? 'approved' : 'rejected'} ticket #${ticket.ticketNumber}`,
      body:    `${session!.user.name} has ${decision === 'APPROVED' ? '✅ approved' : '❌ rejected'} the approval request${note ? `: "${note}"` : '.'}`,
      ticketId: id,
    },
  }).catch(() => {})

  // Activity log
  await prisma.ticketActivity.create({
    data: {
      ticketId: id, actorId: userId,
      type: 'MANAGER_APPROVAL_RESPONDED',
      meta: JSON.stringify({ decision, note }),
    },
  }).catch(() => {})

  return successResponse(updated)
}
